diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..ae44010ec97b 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4607,6 +4607,27 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+
+    // select (X && Y), true, Y --> Y where X && Y = select X, Y, false
+    // select (X || Y), false, Y --> Y where X || Y = select X, true, Y
+    if (match(TrueVal, m_One())) {
+      // (select X, Y, false) is equivalent to (X && Y)
+      // We have: select (X && Y), true, Y
+      // If X is false, result is Y. If X is true and Y is false, result is Y.
+      // If X and Y are true, the result would be true, but we return Y which
+      // is true in that case. So we always return Y.
+      if (match(Cond, m_Select(m_Value(X), m_Specific(FalseVal), m_ZeroInt())))
+        return FalseVal;
+    }
+    if (match(TrueVal, m_ZeroInt())) {
+      // (select X, true, Y) is equivalent to (X || Y)
+      // We have: select (X || Y), false, Y
+      // If X is true, result is false. If X is false and Y is true, result is true.
+      // If X and Y are false, the result would be false, but we return Y which
+      // is false in that case. So we always return Y.
+      if (match(Cond, m_Select(m_Value(X), m_One(), m_Specific(FalseVal))))
+        return FalseVal;
+    }
   }

   // select ?, X, X -> X

